Here's a minimal API endpoint that accepts multiple images + a description via `multipart/form-data`:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure the request is multipart/form-data
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync();

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images"); // matches <input name="images" />

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var dest = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(dest);
        await file.CopyToAsync(stream);
        saved.Add(dest);
    }

    return Results.Ok(new { description, uploadedFiles = saved });
})
.DisableAntiforgery()                      // needed when there's no AF token
.Accepts<IFormFile>("multipart/form-data"); // OpenAPI hint

app.Run();
```

**Key points:**

- **`ConfigureKestrel`** — raises the default 30 MB body limit to 50 MB. Without this, large uploads get a `413`.
- **`ReadFormAsync`** — parses the multipart body; `form.Files` gives you the uploaded files, `form["description"]` gives the text field.
- **`DisableAntiforgery`** — required in .NET 8+ for form endpoints that don't send an antiforgery token (typical for APIs).
- Content-type is checked per file to reject non-images early.

**Example `curl` to test it:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=Vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
